/**
 * GoTable (web) — the PrimeReact DataTable orchestrator.
 *
 * All business logic lives in useTableState (hooks/useTableState.ts).
 * This file is web-only: it contains JSX and PrimeReact imports.
 *
 * @typeParam T — the row data type, e.g. `<Datatable<ICareerItem> ... />`
 */
import React, { useMemo } from "react";
import "./style.scss";
import type { IColumn, IDataTableProps } from "@lmb-it/kitsconcerto-types";
import {
    DataTable as PrimeTable,
    type DataTableSelectionSingleChangeEvent,
    type DataTableValueArray,
} from "primereact/datatable";
import { Column as PrimeColumn } from "primereact/column";
import { Button } from "../../_compat";
import { Skeleton } from "primereact/skeleton";
import {KitsMultiSelect} from "../../form/selects";

import { TableContext } from "./context";
import { defaultText } from "./constants";
import { useTableState } from "./hooks/useTableState";
import TableHeader from "./components/TableHeader";
import Pagination from "./components/Pagination";
import columnFunction from "./components/Column";
import { Flex, useLanguage } from "../../_compat";
import { useComponentDefaults, useResolvedStyle } from "../../hooks";

export { useTable } from "./context";
export { TableContext };

const Datatable = <T extends Record<string, any> = any,>({ ref, ...props }: IDataTableProps<T>) => {
    const {
        style,
        text = defaultText,
        columnsPicker = true,
        // GoTable-specific props — destructured to prevent leaking to PrimeTable DOM
        skeleton: _skeleton,
        stateful: _stateful,
        globalSearch: _globalSearch,
        keyColumn: _keyColumn,
        service: _service,
        serviceRevalidateDeps: _serviceRevalidateDeps,
        headless: _headless,
        multiSorting: _multiSorting,
        rowLockable: _rowLockable,
        rowExpansionTemplate: _rowExpansionTemplate,
        onSelectChange: _onSelectChange,
        tableSize: _tableSize,
        debounceFilterWaitTime: _debounceFilterWaitTime,
        filterMode: _filterMode,
        data: _data,
        exportPDFButton: _exportPDFButton,
        exportCSVButton: _exportCSVButton,
        moreButtons: _moreButtons,
        tableTitle: _tableTitle,
        scrollHeight: _scrollHeight,
        resizableColumns: _resizableColumns,
        selectionMode: _selectionMode,
        columns: _columns,
        ...rest
    } = props;

    const state = useTableState<T>(props, ref);

    const {
        tableRef,
        refValues,
        isLoading,
        dataList,
        globalFilterValue,
        visibleColumns,
        expandedRows,
        setExpandedRows,
        isSelectable,
        selections,
        setSelections,
        serverSideRequest,
        lockedRows,
        isAnyFilter,
        allowExpansion,
        pagination,
        conditionalProps,
        onColumnToggle,
        onGlobalFilterChange,
        onClearFilter,
        onClearCache,
        toggleLock,
        columns,
        onRowSelect,
        onSelectChange,
        selectionMode,
        tableSize,
        resizableColumns,
        scrollHeight,
        stateful,
        globalSearch,
        headless,
        multiSorting,
        rowLockable,
        rowExpansionTemplate,
        service,
        keyColumn,
        staticData,
        exportPDFButton,
        exportCSVButton,
        moreButtons,
        tableTitle,
        debounceFilterWaitTime,
        filterMode,
        refresh,
    } = state;

    const {t} = useLanguage();

    // ── Theme integration: read Table element slots from kitsTheme ──
    const {elementStyles} = useComponentDefaults('Table', {} as any);

    const rootStyle = useResolvedStyle(elementStyles.root || {});
    const thStyle = useResolvedStyle(elementStyles.th || {});
    const headerStyle = useResolvedStyle(elementStyles.header || {});
    const headerRowStyle = useResolvedStyle(elementStyles.headerRow || {});
    const headerCellStyle = useResolvedStyle(elementStyles.headerCell || {});
    const bodyRowStyle = useResolvedStyle(elementStyles.bodyRow || {});
    const bodyCellStyle = useResolvedStyle(elementStyles.bodyCell || {});
    const paginatorStyle = useResolvedStyle(elementStyles.paginator || {});
    const paginatorPageButtonStyle = useResolvedStyle(elementStyles.paginatorPageButton || {});
    const paginatorActivePageButtonStyle = useResolvedStyle(elementStyles.paginatorActivePageButton || {});
    const paginatorRowsPerPageStyle = useResolvedStyle(elementStyles.paginatorRowsPerPage || {});
    const emptyMessageStyle = useResolvedStyle(elementStyles.emptyMessage || {});

    const overwriteText = useMemo(() => text ?? {}, [text]);
    const sortBy = serverSideRequest.sortBy;

    // Build skeleton rows with visible Skeleton components
    const skeletonList = useMemo(() => {
        const list: Record<string, any>[] = [];
        for (let i = 0; i < serverSideRequest.length; i++) {
            const obj: Record<string, any> = { [keyColumn]: i };
            columns
                .filter((c) => visibleColumns.some((v) => v.name === c.name))
                .forEach((col, index) => {
                    if (col.name && col.name !== keyColumn) {
                        obj[col.name] = (
                            <Skeleton key={index} className={"mb-2"} style={col.globalStyle} />
                        );
                    }
                });
            list.push(obj);
        }
        return list;
    }, [columns, visibleColumns, serverSideRequest, keyColumn]);

    // Internal column rendering uses IColumn<any> — T is erased at runtime.
    // columnFunction is a pure function (no hooks) — safe to call in .map().
    const columnRender = (field: IColumn<any>, index: number) =>
        columnFunction({
            index,
            field,
            serverSideRequest,
            tableSize,
            keyColumn,
            isLoading,
            debounceFilterWaitTime,
            filterMode,
            t,
            themeHeaderCellStyle: headerCellStyle,
            themeBodyCellStyle: bodyCellStyle,
        });

    const lockTemplate = (
        rowData: T,
        options: { frozenRow?: boolean; rowIndex: number },
    ) => {
        const icon = options.frozenRow ? "pi pi-lock" : "pi pi-lock-open";
        const disabled = options.frozenRow ? false : lockedRows.length >= 2;
        return (
            <Button
                type="button"
                icon={icon}
                disabled={disabled}
                className="p-button-sm p-button-text"
                onClick={() =>
                    toggleLock(
                        rowData,
                        options.frozenRow,
                        options.rowIndex,
                    )
                }
            />
        );
    };

    const isScrollHeightAuto = scrollHeight === "auto";

    return (
        <TableContext.Provider
            value={{
                columns: columns as IColumn<any>[],
                onGlobalFilterChange,
                globalFilterValue,
                reloadClickHandler: refresh,
                pagination,
                onClearFilter,
                onClearCache,
                dataList,
                serverSideRequest,
                buttons: {
                    exportAsCSV: exportCSVButton,
                    exportAsPdf: exportPDFButton,
                    moreButtons: moreButtons as ((context: any) => React.ReactNode[]) | undefined,
                },
                rowLockable,
                fileName: tableTitle ?? "my-table",
                rowExpansionTemplate,
                isLoading,
                visibleColumns,
                resizableColumns,
                refValues: refValues as any,
                lockedRows,
                tableRef: tableRef as any,
                globalSearch,
                toggleLock: toggleLock as any,
                keyColumn,
                stateful,
                text: {
                    clearCache: "Clear Cache",
                    filter: [],
                    ...defaultText,
                    ...overwriteText,
                },
            }}
        >
            <Flex
                flexDirection={"column"}
                w={"full"}
                className={
                    "table-container " + (isScrollHeightAuto ? "scroll-height-auto" : "")
                }
            >
                {!!tableTitle && (
                    <Flex className={"surface-900"} px={10} py={5}>
                        <h2 className={"text-50"}>{tableTitle}</h2>
                    </Flex>
                )}
                {/* @ts-ignore — cross-platform type conflict: moduleSuffixes resolves native DataTableProps first */}
                <PrimeTable
                    ref={tableRef}
                    value={
                        (isLoading ? skeletonList : dataList) as DataTableValueArray
                    }
                    paginator={!!staticData}
                    width={"100%"}
                    style={{...rootStyle, ...style}}
                    className={"theme-scroll"}
                    pt={{
                        thead: { style: thStyle },
                        header:{style: headerStyle},
                        headerRow: { style: headerRowStyle },
                        bodyRow: { style: bodyRowStyle },
                        paginator: {
                            root: { style: paginatorStyle },
                            pageButton: { style: paginatorPageButtonStyle },
                            firstPageButton: { style: paginatorPageButtonStyle },
                            nextPageButton: { style: paginatorPageButtonStyle },
                            lastPageButton: { style: paginatorPageButtonStyle },
                            prevPageButton: { style: paginatorPageButtonStyle },
                            current: { style: paginatorActivePageButtonStyle },
                            RPPDropdown: { root: { style: paginatorRowsPerPageStyle } },
                        },
                        emptyMessage: { style: emptyMessageStyle },
                    }}
                    rows={serverSideRequest.length}
                    rowsPerPageOptions={staticData ? [15, 25, 30, 50, 100] : undefined}
                    tableStyle={{ minWidth: "50rem", maxHeight: "100%" }}
                    paginatorTemplate="RowsPerPageDropdown FirstPageLink PrevPageLink CurrentPageReport NextPageLink LastPageLink"
                    currentPageReportTemplate="{first} to {last} of {totalRecords}"
                    size={tableSize}
                    dataKey={keyColumn}
                    emptyMessage={text.emptyMessage}
                    header={
                        !headless
                            ? () => (
                                  <TableHeader>
                                      {columnsPicker && (
                                          <KitsMultiSelect
                                              id={"column-picker"}
                                              valueMode={'text'}
                                              localProps={{
                                                  maxSelectedLabels:0
                                              }}
                                              value={visibleColumns.map((v) => v.name)}
                                              list={(columns as any[]).map((c) => ({ label: c.label, value: c.name }))}
                                              withFilter
                                              onChange={(e: any) =>
                                                  onColumnToggle(e.value as string[])
                                              }
                                              inputSize="sm"
                                          />
                                      )}
                                  </TableHeader>
                              )
                            : undefined
                    }
                    showGridlines={true}
                    multiSortMeta={multiSorting ? sortBy : undefined}
                    sortMode={multiSorting ? "multiple" : "single"}
                    sortField={
                        !multiSorting && sortBy.length > 0 ? sortBy[0]?.field : undefined
                    }
                    sortOrder={
                        !multiSorting && sortBy.length > 0 ? sortBy[0]?.order : undefined
                    }
                    footer={service ? () => <Pagination /> : undefined}
                    filters={
                        isLoading || !isAnyFilter ? undefined : serverSideRequest.filters
                    }
                    onRowSelect={isSelectable ? onRowSelect : undefined}
                    resizableColumns={resizableColumns}
                    columnResizeMode={resizableColumns ? "expand" : undefined}
                    filterDisplay={isAnyFilter ? "row" : undefined}
                    selectionMode={
                        isSelectable
                            ? (selectionMode as "single" | "radiobutton" | undefined)
                            : undefined
                    }
                    selection={isSelectable ? selections : undefined}
                    onSelectionChange={
                        isSelectable
                            ? (e: DataTableSelectionSingleChangeEvent<T[]>) => {
                                  setSelections(Array.isArray(e.value) ? e.value : [e.value]);
                                  onSelectChange && onSelectChange(e as Parameters<NonNullable<typeof onSelectChange>>[0]);
                              }
                            : undefined
                    }
                    removableSort
                    expandedRows={expandedRows}
                    onRowToggle={(e) => setExpandedRows(e.data)}
                    rowExpansionTemplate={rowExpansionTemplate}
                    {...conditionalProps}
                    {...rest}
                >
                    {allowExpansion && (
                        <PrimeColumn expander={allowExpansion} style={{ width: "5rem" }} />
                    )}
                    {(columns as IColumn<any>[])
                        .filter((c) => visibleColumns.some((v) => v.name === c.name))
                        .map(columnRender)}
                    {!!rowLockable && (
                        <PrimeColumn
                            style={{ flex: "0 0 4rem" }}
                            body={lockTemplate}
                            frozen
                            alignFrozen={"left"}
                        />
                    )}
                </PrimeTable>
            </Flex>
        </TableContext.Provider>
    );
};

export default Datatable;
